def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        if ratio > 2:
            base = ratio ** 2
            penalty = 0
            for p in range(1, 5):
                penalty += (ratio ** (2 * p)) / (p ** 2 + 1)
            score = base + penalty
            if ratio > 5:
                extra_penalty = 0
                for q in range(1, 3):
                    extra_penalty += np.log1p(ratio ** q) * q
                score += extra_penalty
        elif 1 < ratio <= 2:
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else (-1 if j % 2 == 0 else 1)
                term = sign * (ratio ** (j/2)) / (j + 1)
                score += term
            multiplier = 20 if ratio > 1.8 else 12 if ratio > 1.2 else 8
            score = abs(score) * multiplier
        else:
            partial_sum = 0
            for x in range(1, 10):
                factor = ((-1) ** (x+1)) * (ratio ** x) / (x * (x + 1))
                partial_sum += factor
            multiplier = 25 if ratio < 0.25 else 18 if ratio < 0.5 else 10
            score = abs(partial_sum) * multiplier
            if 0.75 < ratio <= 1:
                bonus = 0
                for b in range(1, 5):
                    bonus += np.sqrt(ratio ** b) / (b + 2)
                score += bonus
        if np.isnan(score) or score < 0:
            priorities[i] = np.inf
        else:
            priorities[i] = score
    return priorities
